import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {
    public static void main(String[] args) throws IOException {
        String userInput = "../secretfile.txt";
        String basePath = "resources/"; // Specify the base directory where files are allowed to be accessed

        if (!userInput.contains("..") && userInput.endsWith(".txt")) {
            File file = new File(basePath + userInput);

            if (file.exists()) {
                byte[] content = Files.readAllBytes(Paths.get(basePath, userInput));
                System.out.println(new String(content));
            } else {
                System.out.println("File not found");
            }
        } else {
            System.out.println("Invalid file path");
        }
    }
}

